    {
      "keystrokes": "ls -l tcc\n",
      "duration": 0.1
    },
    {
      "keystrokes": "make tcc 2>&1 | tail -10\n",
      "duration": 10.0
    },
    {
      "keystrokes": "apt install -y file 2>&1 | tail -5\n",
